%[text] # Modelo en SS del sistema de Steer by Wire
%[text:tableOfContents]{"heading":"Tabla de contenidos"}
clc; clear;
%%
%[text] ## MODELADO DEL SISTEMA EN SS
%[text] ### Constantes del sistema
% Parámetros del motor
% Motor BLDC/DC equivalente realista - referencia Mosrac U13060 48 V
Lm  = 0.42e-3;        % [H]
Rm  = 0.135;          % [Ohm]
Bm  = 1e-3;           % [N.m.s/rad] mantener estimado
Jm  = 1.0e-3;         % [kg.m^2]
Ke  = 0.6;            % [V.s/rad] equivalente DC coherente con Kt
Kt  = 0.6;            % [N.m/A]
Vm_sat = 48;          % [V]

% Límites publicados para validar resultados de simulación
I_cont_motor = 30;    % [A]
I_peak_motor = 70;    % [A]
T_cont_motor = 18;    % [N.m]
T_peak_motor = 40;    % [N.m]
rpm_max_motor = 800;  % [rpm]

Ka  = 3500;           % [N·m/rad] Rigidez acoplamiento motor-carga

% Parámetros de la cremallera
Bcr = 1.032;          % [N·s/m]
Mcr = 2.0;            % [kg]
rL  = 0.115;          % [m/rad] relación y_c/delta; 35 deg ~= 70 mm de rack

% Transmisión motor-cremallera: reducción + ball screw
% Referencia de arquitectura RWA: motor -> belt drive -> ball screw -> rack.
% G_bs es la relación motor/tornillo: el motor gira G_bs vueltas por cada
% vuelta del tornillo. lead_bs es el avance lineal del tornillo por vuelta.
rP_pinion_ref = 0.012;     % [m] radio primitivo piñón original, solo referencia
G_bs = 1.0;                % [-] reducción motor/screw
lead_bs = 32e-3;           % [m/rev] avance del ball screw
eta_bs = 1.0;              % [-] eficiencia ideal en la cinemática del modelo
rP_kin = lead_bs/(2*pi*G_bs);      % [m/rad] relación cinemática y_c/theta_m
rP = rP_kin;                      % [m/rad] radio equivalente usado en la planta

% Parámetros de la rueda
Bf  = 30;             % [N·m·s/rad]
Kf  = 26000;          % [N·m/rad]
Jf  = 0.270;          % [kg·m^2]

% Parámetros de perturbación
Ff_cte = 9;              % Fza fricción en la cremallera [N]
Tf_cte = 2;              % Torque fricción en el pivote de la rueda [Nm]
%%
%[text] ### Matrices en SS
%[text] Estado: x = \[ $i\_m$; $\\theta\_m$; $\\omega\_m$; $y\_c$; $v\_c$; $\\delta$; $\\psi$\]
%[text] 7 estados, 1 entrada de control, 3 perturbaciones
% Matriz A (7x7)
A = zeros(7,7);

A(1,1) = -Rm/Lm;
A(1,3) = -Ke/Lm;

A(2,3) = 1;

A(3,1) = Kt/Jm;
A(3,2) = -Ka/Jm;
A(3,3) = -Bm/Jm;
A(3,4) = Ka/(rP * Jm);

A(4,5) = 1;

A(5,2) = Ka/(rP * Mcr);
A(5,4) = -(2 * Kf/rL^2 + Ka/rP^2) / Mcr;
A(5,5) = -Bcr/Mcr;
A(5,6) = 2 * Kf/(rL * Mcr);

A(6,7) = 1;

A(7,4) = Kf/(rL * Jf);
A(7,6) = -Kf/Jf;
A(7,7) = -Bf/Jf;
%[text] Matrices de Control y Perturbaciones
% Matriz de entrada de control (Vm)
Bc = zeros(7,1);
Bc(1) = 1/Lm;

% Matriz de perturbaciones [Ff; Tf; Ta]
Bd = zeros(7,3);
Bd(5,1) = -1/Mcr;       % Ff: fuerza de fricción en la cremallera
Bd(7,2) = -1/Jf;        % Tf: torque de fricción en la rueda
Bd(7,3) = -1/Jf;        % Ta: torque de autoalineamiento

% Matriz de entrada completa
B_SS = [Bc Bd]; % Se usa para el bloque SS de simulink

%[text] Matrices de salida, de sensor y de performance
% Estado: x = [im; thetam; omegam; ycr; vcr; delta; psi]
% Matriz C_sensor, extrae y_c (posición lineal de la cremallera)
C_s = [0 0 0 1 0 0 0];

% Matriz C_Performance, extrae delta
C_p = zeros(1,7);
C_p(1,6)=1;

C_SS = eye(7); % Se usa para el bloque SS de simulink. Todos los estados observables

D_SS = zeros(7,4); % Se usa para el bloque SS de simulink
D = zeros(1);

% Tiempo de muestreo del sensor discretizado
Ts = 0.02;           % [s] Alineado con el sensado / comunicación en Simulink

% Modelo discreto de la planta (disponible para los subsistemas digitales)
sys_SS_d = c2d(ss(A, B_SS, C_SS, D_SS), Ts, 'zoh');
A_d = sys_SS_d.A;
B_SS_d = sys_SS_d.B;
C_SS_d = sys_SS_d.C;
D_SS_d = sys_SS_d.D;

Bc_d = B_SS_d(:,1);
Bd_d = B_SS_d(:,2:end);

%%
%[text] ### Análisis de observabilidad y controlabilidad
%[text] Las matrices de controlabilidad y observabilidad de este sistema están muy mal condicionadas debido a diferencias de hasta 18 órdenes de magnitud entre sus valores singulares, por lo que la tolerancia automática que usa rank en MATLAB —basada en la norma de la matriz y la precisión numérica— clasifica erróneamente varios valores singulares no nulos como “cero”, reduciendo artificialmente el rango; al fijar manualmente una tolerancia más pequeña (p. ej. 1e-3), se evita que la escala extrema de la matriz distorsione el cálculo y se recupera el rango estructural correcto del sistema, garantizando que la evaluación de controlabilidad y observabilidad sea coherente con la dinámica real del modelo. 
% Verificación de controlabilidad y observabilidad
Co = ctrb(A,Bc);
rankCo = rank(Co,1e-3) %[output:09bdada9]
Ob = obsv(A,C_s);
rankOb = rank(Ob,1e-3) %[output:6ff67f37]
%[text] Como los rangos son igual a 7, el sistema es controlable desde $V\_m$ y observable desde $y\_c$.
%%
%[text] ### Análisis de polos de la matriz A (Polos del sistema a lazo abierto)
polos_LA = eig(A) %[output:198aafa6]
%%
%[text] ### Respuesta de $\\delta(t)$ a entrada escalón
% Sistema en espacio de estados
sys_fw = ss(A, Bc, C_p, D);

% Simulación: entrada escalón desde t = 1s
t = 0:0.001:10;
u = zeros(size(t));
u(t >= 0) = 12;

[y, t_out] = lsim(sys_fw, u, t); %[output:2785c117]
% Gráfico
plot(t_out, y*180/pi, 'LineWidth', 2) %[output:2c40b12c]
xlabel('Tiempo [s]') %[output:2c40b12c]
ylabel('Ángulo rueda \delta [°]') %[output:2c40b12c]
title('Rta \delta(t) a entrada escalón escalón de 12 V') %[output:2c40b12c]
grid on %[output:2c40b12c]
%%
%[text] ### Función de transferencia $G(s) = \\delta(s)/V\_m(s)$
% Obtener la función de transferencia G(s) = delta(s)/Vm(s)
[num, den] = ss2tf(A, Bc, C_p, D);
% Mostrar como función de transferencia
G = tf(num, den) %[output:30731268]
%%
%[text] ## CONTROLADOR
%[text] ### Controlador LQR - Con performance $\\delta$ y entrada Vm (funcionando, pero reemplazado por el LQR con acción integral)
% Valores máximos
im_max   =  40;           % [A]   pico de corriente permitido por el driver
del_max  =  0.61;         % [rad] 35°  (dato de diseño)
Vm_max   =  48;           % [V]   tensión del inversor

% Matriz C_Performance, extrae la corriente y delta
C_p = zeros(1,7);
C_p(1,6)=1;

% Ponderaciones relativas (α) - Valores de penalizaciones
alpha = 1;

% Matriz Qx
y_max = del_max;
%y_max = [im_max  thm_max  wmm_max  yc_max  vc_max  del_max  psf_max];
Qy  = diag( alpha ./ (y_max.^2) );

Qx = C_p'*Qy*C_p;

% Matriz Qu
%rho = 0.5;
rho = 0.15;
Qu  = rho / Vm_max^2;        % o  rho / Vm_max^2  si querés afinar con un ρ

% Ganancia de la realimentación de estados
K_lqr  = lqr(A, Bc, Qx, Qu) %[output:919dd200]
% Ganancia de la referencia
kr = -1 / (C_p * ((A - Bc*K_lqr) \ Bc)) %[output:9753726d]
%%
%[text] ### LQRI (acción integral) - Con performance $\\delta$ y entrada Vm
%[text] ![](text:image:56da)
%[text] ![](text:image:59dd)
% Matriz C_Performance, extrae delta
C_p = zeros(1,7);
C_p(1,6)=1;

% Modelo aumentado continuo:
% x_dot = A x + Bc u
% z_dot = delta - r = C_p x - r
A_aug_c = [A   zeros(7,1)
           C_p     0     ];

Bc_aug_c = [Bc
            0];

Br_aug_c = [zeros(7,1)
            -1];

% Valores máximos
del_max  =  0.61;         % [rad] 35°  (dato de diseño)
Vm_max   =  48;           % [V]   tensión del inversor

% Matriz Qx
alpha1 = 50; %[control:editfield:8a44]{"position":[10,12]}
alpha2 = 6; %[control:editfield:37f0]{"position":[10,11]}
alpha = [alpha1, alpha2];
y_max = del_max;
z_max = 0.04; %[control:editfield:5808]{"position":[9,13]}

Qy  = diag( alpha(1) ./ (y_max.^2) );
Qx = [C_p'*Qy*C_p zeros(7,1)
      zeros(1,7)      alpha(2)/z_max^2];

% Matriz Qu
rho = 0.07; %[control:editfield:6145]{"position":[7,11]}
Qu  = rho / Vm_max^2;       % o  rho / Vm_max^2  si querés afinar con un ρ

% Ganancia de la realimentación de estados continua
K_aug  = lqr(A_aug_c, Bc_aug_c, Qx, Qu);
K = K_aug(1:7);
Ki = K_aug(8);

ang_step = 10; %[deg] Utilizado como ángulo de referencia en simulink %[control:editfield:2f7b]{"position":[12,14]}
vel_kmh = 100;  %[km/h] Utilizado para calcular el torque de autoalineamiento de perturbación. %[control:editfield:58f6]{"position":[11,14]}
%[text] %[text:anchor:H_D0542EAB] Combinaciones que funcionan:
%[text] ![](text:image:88cb)
%[text] ![](text:image:05dc)
%%
%[text] ## SENSORES
%[text] ### Sensor de posición lineal de cremallera $y\_c$
%[text] Usando el controlador LQRI, se busca la banda de lazo cerrado $f\_{bw}$
Acl = A_aug_c - Bc_aug_c * K_aug;
Bcl = Br_aug_c;                 % entrada: referencia
Ccl = [0 0 0 0 0 1 0 0];        % salida: delta
Dcl = 0;

sys_cl = ss(Acl, Bcl, Ccl, Dcl);

% fbw en rad/s y en Hz
wbw = bandwidth(sys_cl)       % [rad/s] (frecuencia -3 dB) %[output:8b54d3db]
fbw = wbw / (2*pi)            % [Hz] %[output:4b5f6913]
%[text] Esta es la frecuencia límite a la que el sistema puede seguir a la señal de referencia. A la frecuencia de $f\_{bw}$=0.7943 Hz la magnitud de la respuesta cae 3 dB (se pierde el 50% de la potencia). En una sinusoide esto se traduce a una pérdida de amplitud de 1 a 0.707. Esto puede verse en la siguiente imágen, que al excitar al sistema con una sinusoidal de amplitud 1 y frecuencia $w\_{bw} = 4.9906$ rad/s, la respuesta no solo se atrasa respecto de la ref, sino que su amplitud se reduce a un aproximadamente un 70% de la amplitud de la entrada.
%[text] ![](text:image:4ee3)
%[text] Si la señal de referencia tiene cambios a una frecuencia mayor, el sistema no alcanzará a responder correctamente.
%[text] La frecuencia de corte $f\_c$ del sensor debe ser entre 5 a 10 veces mayor que la frecuencia $f\_{bw}$ para garantizar que el sistema logre seguir correctamente a la referencia. Por eso se selecciona:
fc = 10*fbw        % [Hz] %[output:6581bf4e]
%[text] La constante de tiempo en un filtro pasa-bajos es:
tau = 1/(2*pi*fc)   % [s] %[output:30e3bd4a]
%[text] Un sensor de tipo encoder puede modelarse como un filtro de primer orden de la siguiente manera:
Ts_sensor = 0.01;        % [s] 100 Hz, medicion retenida para el lazo
tau_sensor = 0.001;       % [s] dinamica del sensor
sigma_yc = 8.08e-5;      % [m] desviación estándar = 0.081 mm
q_yc = 3.42e-5;          % [m] cuantizacion = 0.034 mm
%[text] ## Sensor de Vm
%[text] Para realimentar hacia el observador
% Sensor / medicion de tension aplicada al motor
Ts_Vm_sensor  = 1e-3;        % [s] 1 kHz
tau_Vm_sensor = 1e-3;        % [s] dinamica rapida de medicion

Vm_fs = 60;                  % [V] rango bipolar asumido: -60 a +60 V
q_Vm  = 120/4096;            % [V] cuantizacion equivalente 12 bits bipolar
                             % q_Vm = 0.0293 V

e_Vm_max = 0.005*Vm_fs;      % [V] error conservador: 0.5% FS
                             % e_Vm_max = 0.30 V

% Si usas Uniform Random Number:
Vm_noise_min = -e_Vm_max;
%%
%[text] ## OBSERVADOR
%[text] ### Filtro de Kalman continuo
%[text] ![](text:image:8ecf)
Gw = eye(7);   % ruido de proceso actuando en todos los estados

%% Covarianza de proceso Q
    % Más grandes → el filtro confía más en la medición, menos en el modelo (respuesta más rápida pero más ruidosa).
q1 = 0.1;     % im
q2 = 0.1;       % theta_m
q3 = 0.1;       % omega_m
q4 = 0.01;       % y_cr
q5 = 0.01;       % v_cr
q6 = 0.01;       % delta
q7 = 0.01;       % psi

Q = diag([q1 q2 q3 q4 q5 q6 q7]);


%% Covarianza de medición R
    % Un solo sensor -> escalar.
    % R más chico -> confía más en el sensor de cremallera.
    % R más grande -> lo suaviza y confía más en el modelo.
R = 5*(sigma_yc)^2; % [m] desviación estándar del sensor de posición lineal


%% Cálculo de la ganancia de Kalman continua
% El controlador y observador quedan en continuo; el sensor puede entregar
% una medición muestreada/retenida mediante un ZOH en Simulink.
[L, P, E] = lqe(A, Gw, C_s, Q, R);
%[text] ![](text:image:9132)
%%
%[text] ## 
%%
%[text] ## Análisis extra
sys_delta = ss(A, Bc, C_p, 0);
bode(sys_delta) %[output:97f1abd3]
grid on %[output:97f1abd3]

